1	<script setup lang="ts">
2	import { ref, computed, nextTick } from 'vue';
3	import { useRouter } from 'vue-router';
4	import { useAuth } from '@/entities/user/model/use-auth.js';
5	
6	const router = useRouter();
7	const { login, verifyPin, loginWithPasskey } = useAuth();
8	
9	const email = ref('');
10	const pin = ref('');
11	const step = ref<'email' | 'pin'>('email');
12	const error = ref('');
13	const loading = ref(false);
14	const passkeyLoading = ref(false);
15	const pinInputRef = ref<HTMLInputElement | null>(null);
16	const passkeyBroken = ref(false);
17	const passkeyAnnounce = ref('');
18	
19	const passkeySupported = computed(
20	  () => !passkeyBroken.value && typeof window !== 'undefined' && !!window.PublicKeyCredential,
21	);
22	
23	async function handleSendPin() {
24	  error.value = '';
25	  loading.value = true;
26	  try {
27	    await login(email.value);
28	    step.value = 'pin';
29	    await nextTick();
30	    pinInputRef.value?.focus();
31	  } catch (e) {
32	    error.value = e instanceof Error ? e.message : 'Failed to send PIN';
33	  } finally {
34	    loading.value = false;
35	  }
36	}
37	
38	async function handleVerifyPin() {
39	  error.value = '';
40	  loading.value = true;
41	  try {
42	    await verifyPin(email.value, pin.value);
43	    await router.push('/');
44	    await nextTick();
45	    const heading = document.querySelector<HTMLElement>('#main-content h2, #main-content h1');
46	    if (heading) { heading.tabIndex = -1; heading.focus(); }
47	  } catch (e) {
48	    error.value = e instanceof Error ? e.message : 'Invalid PIN';
49	  } finally {
50	    loading.value = false;
51	  }
52	}
53	
54	function getPasskeyErrorMessage(e: unknown): string {
55	  if (e instanceof DOMException) {
56	    if (e.name === 'NotAllowedError') return 'Authentication was cancelled. Please try again.';
57	    if (e.name === 'SecurityError') return "This action isn't allowed on this domain";
58	    if (e.name === 'NotSupportedError') return 'Your browser does not support passkeys. Please use PIN login.';
59	  }
60	  return 'Passkey authentication failed. Please try PIN login.';
61	}
62	
63	async function handlePasskeyLogin() {
64	  if (!email.value) {
65	    error.value = 'Please enter your email first';
66	    return;
67	  }
68	  error.value = '';
69	  passkeyLoading.value = true;
70	  try {
71	    await loginWithPasskey(email.value);
72	    passkeyAnnounce.value = 'Sign in successful. Redirecting...';
73	    await router.push('/');
74	    await nextTick();
75	    const heading = document.querySelector<HTMLElement>('#main-content h2, #main-content h1');
76	    if (heading) { heading.tabIndex = -1; heading.focus(); }
77	  } catch (e) {
78	    if (e instanceof DOMException && e.name === 'NotSupportedError') {
79	      passkeyBroken.value = true;
80	    }
81	    error.value = getPasskeyErrorMessage(e);
82	  } finally {
83	    passkeyLoading.value = false;
84	  }
85	}
86	</script>
87	
88	<template>
89	  <div class="flex min-h-screen items-center justify-center bg-background p-4">
90	    <div class="w-full max-w-sm space-y-6">
91	      <div class="text-center">
92	        <h1 class="text-2xl font-bold">Sign in</h1>
93	        <p aria-live="polite" class="mt-2 text-sm text-muted-foreground">
94	          {{ step === 'email' ? 'Enter your email to receive a login code' : 'Enter the code sent to your email' }}
95	        </p>
96	      </div>
97	
98	      <div
99	        v-if="error"
100	        id="login-error"
101	        role="alert"
102	        aria-live="assertive"
103	        class="rounded-md bg-destructive/10 p-3 text-sm text-destructive"
104	      >
105	        {{ error }}
106	      </div>
107	
108	      <!-- Passkey status announcer for screen readers -->
109	      <div aria-live="polite" aria-atomic="true" class="sr-only">{{ passkeyAnnounce }}</div>
110	
111	      <!-- Step 1: Email -->
112	      <form v-if="step === 'email'" @submit.prevent="handleSendPin" class="space-y-4">
113	        <div>
114	          <label class="block text-sm font-medium mb-1.5" for="email">Email</label>
115	          <input
116	            id="email"
117	            v-model="email"
118	            type="email"
119	            required
120	            autofocus
121	            placeholder="you@example.com"
122	            :aria-describedby="error ? 'login-error' : undefined"
123	            :aria-invalid="error ? 'true' : undefined"
124	            class="w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus:outline-hidden focus:ring-2 focus:ring-ring"
125	          />
126	        </div>
127	
128	        <!-- Passkey sign-in button (only shown when supported) -->
129	        <template v-if="passkeySupported">
130	          <button
131	            type="button"
132	            :disabled="passkeyLoading || loading"
133	            :aria-busy="passkeyLoading"
134	            @click="handlePasskeyLogin"
135	            class="w-full flex items-center justify-center gap-2 rounded-md border border-input bg-background px-4 py-2 text-sm font-medium hover:bg-muted disabled:opacity-50"
136	          >
137	            <span
138	              v-if="passkeyLoading"
139	              class="inline-block h-4 w-4 animate-spin rounded-full border-2 border-current border-t-transparent"
140	              aria-hidden="true"
141	            />
142	            <span v-else>🔑</span>
143	            {{ passkeyLoading ? 'Signing in...' : 'Sign in with a passkey' }}
144	          </button>
145	
146	          <div class="flex items-center gap-3">
147	            <div class="h-px flex-1 bg-border" />
148	            <span class="text-xs text-muted-foreground">or</span>
149	            <div class="h-px flex-1 bg-border" />
150	          </div>
151	        </template>
152	
153	        <button
154	          type="submit"
155	          :disabled="loading || passkeyLoading"
156	          :aria-busy="loading"
157	          class="w-full rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground hover:bg-primary/90 disabled:opacity-50"
158	        >
159	          {{ loading ? 'Sending...' : 'Send login code' }}
160	        </button>
161	      </form>
162	
163	      <!-- Step 2: PIN -->
164	      <form v-else @submit.prevent="handleVerifyPin" class="space-y-4">
165	        <div>
166	          <label class="block text-sm font-medium mb-1.5" for="pin">Verification code</label>
