2	import { ref, nextTick, computed } from 'vue';
3	import { useStatusAnnouncer } from '@/shared/composables/useStatusAnnouncer.js';
4	
5	const MAX_MESSAGE_LENGTH = 4000;
6	const WARN_THRESHOLD = Math.floor(MAX_MESSAGE_LENGTH * 0.9);
7	
8	interface Message {
9	  role: 'user' | 'assistant';
10	  content: string;
11	  isError?: boolean;
12	}
13	
14	const messages = ref<Message[]>([]);
15	const input = ref('');
16	const isSubmitting = ref(false);
17	const isStreaming = ref(false);
18	const chatContainer = ref<HTMLElement | null>(null);
19	
20	const charCount = computed(() => input.value.length);
21	const isOverLimit = computed(() => charCount.value > MAX_MESSAGE_LENGTH);
22	const isNearLimit = computed(() => charCount.value >= WARN_THRESHOLD && !isOverLimit.value);
23	const canSend = computed(() => !!input.value.trim() && !isSubmitting.value && !isOverLimit.value);
24	const { announceError } = useStatusAnnouncer();
25	
26	async function send() {
27	  if (!canSend.value) return;
28	
29	  const userMessage = input.value;
30	  input.value = '';
31	  messages.value.push({ role: 'user', content: userMessage });
32	  isSubmitting.value = true;
33	
34	  await nextTick();
35	  chatContainer.value?.scrollTo({ top: chatContainer.value.scrollHeight, behavior: 'smooth' });
36	
37	  let assistantIdx = -1;
38	
39	  try {
40	    const orgId = localStorage.getItem('orgId');
41	    const headers: Record<string, string> = { 'Content-Type': 'application/json' };
42	    if (orgId) headers['X-Organization-Id'] = orgId;
43	
44	    const res = await fetch('/api/ai/chat/stream', {
45	      method: 'POST',
46	      headers,
47	      credentials: 'include',
48	      body: JSON.stringify({
49	        message: userMessage,
50	        history: messages.value.slice(0, -1),
51	      }),
52	    });
53	
54	    if (!res.ok || !res.body) {
55	      throw new Error(`HTTP ${res.status}`);
56	    }
57	
58	    messages.value.push({ role: 'assistant', content: '' });
59	    assistantIdx = messages.value.length - 1;
60	    isStreaming.value = true;
61	
62	    const reader = res.body.getReader();
63	    const decoder = new TextDecoder();
64	    let buffer = '';
65	
66	    while (true) {
67	      const { done, value } = await reader.read();
68	      if (done) break;
69	
70	      buffer += decoder.decode(value, { stream: true });
71	      const lines = buffer.split('\n');
72	      buffer = lines.pop() ?? '';
73	
74	      for (const line of lines) {
75	        if (line.startsWith('data: ')) {
76	          try {
77	            const event = JSON.parse(line.slice(6));
78	            if (event.error) {
79	              messages.value[assistantIdx].content = 'Unable to reach AI. Please try again.';
80	              messages.value[assistantIdx].isError = true;
81	            } else if (event.token) {
82	              messages.value[assistantIdx].content += event.token;
83	            }
84	          } catch { /* ignore malformed SSE lines */ }
85	        }
86	      }
87	      await nextTick();
88	      chatContainer.value?.scrollTo({ top: chatContainer.value.scrollHeight, behavior: 'smooth' });
89	    }
90	
91	    if (!messages.value[assistantIdx]?.content) {
92	      messages.value[assistantIdx].content = 'Unable to reach AI. Please try again.';
93	      messages.value[assistantIdx].isError = true;
94	      announceError(messages.value[assistantIdx].content);
95	    }
96	  } catch {
97	    const errMsg = 'Unable to reach AI. Please try again.';
98	    if (assistantIdx >= 0) {
99	      messages.value[assistantIdx].content = errMsg;
100	      messages.value[assistantIdx].isError = true;
101	    } else {
102	      messages.value.push({ role: 'assistant', content: errMsg, isError: true });
103	    }
104	    announceError(errMsg);
105	  } finally {
106	    isSubmitting.value = false;
107	    isStreaming.value = false;
108	    await nextTick();
109	    chatContainer.value?.scrollTo({ top: chatContainer.value.scrollHeight, behavior: 'smooth' });
110	  }
111	}
